import { createSlice, createAsyncThunk, PayloadAction } from '@reduxjs/toolkit';
import { quickLinksService, QuickLink } from '../../services/quickLinksService';

interface QuickLinksState {
  items: QuickLink[];
  loading: boolean;
  error: string | null;
}

const initialState: QuickLinksState = {
  items: [],
  loading: false,
  error: null,
};

export const fetchQuickLinks = createAsyncThunk('quickLinks/fetch', () =>
  quickLinksService.getAll(),
);

export const addQuickLink = createAsyncThunk('quickLinks/add', (link: Omit<QuickLink, 'id'>) =>
  quickLinksService.create(link),
);

export const removeQuickLink = createAsyncThunk('quickLinks/remove', (id: string) =>
  quickLinksService.delete(id),
);

const quickLinksSlice = createSlice({
  name: 'quickLinks',
  initialState,
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(fetchQuickLinks.pending, (state) => { state.loading = true; state.error = null; })
      .addCase(fetchQuickLinks.fulfilled, (state, action: PayloadAction<QuickLink[]>) => {
        state.loading = false;
        state.items = action.payload;
      })
      .addCase(fetchQuickLinks.rejected, (state, action) => {
        state.loading = false;
        state.error = action.error.message ?? 'Failed to load';
      })
      .addCase(addQuickLink.fulfilled, (state, action: PayloadAction<QuickLink>) => {
        state.items.push(action.payload);
      })
      .addCase(removeQuickLink.fulfilled, (state, action) => {
        state.items = state.items.filter((l) => l.id !== action.meta.arg);
      });
  },
});

export default quickLinksSlice.reducer;
