// Placeholder service — wire to real API endpoint when backend is ready.
// Replace MOCK_STORAGE with: apiFetch<QuickLink[]>('/dashboard/quick-links')

export interface QuickLink {
  id: string;
  label: string;
  path: string;
  icon: string;
  color?: string;
}

const STORAGE_KEY = 'linm:dashboard:quick-links';

function readStorage(): QuickLink[] {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]'); }
  catch { return []; }
}

function writeStorage(items: QuickLink[]): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
}

export const quickLinksService = {
  getAll(): Promise<QuickLink[]> {
    return Promise.resolve(readStorage());
  },

  create(link: Omit<QuickLink, 'id'>): Promise<QuickLink> {
    const newLink: QuickLink = { ...link, id: `${Date.now()}-${Math.random().toString(36).slice(2)}` };
    const items = readStorage();
    items.push(newLink);
    writeStorage(items);
    return Promise.resolve(newLink);
  },

  delete(id: string): Promise<void> {
    const items = readStorage().filter((l) => l.id !== id);
    writeStorage(items);
    return Promise.resolve();
  },
};
