import React, { useEffect, useRef } from 'react';
import { mountRootParcel } from 'single-spa';
import styles from './DashboardPage.module.css';

export interface WidgetConfig {
  id: string;
  title: string;
  parcelName?: string;
  cols?: 1 | 2 | 3;
}

// Widget registry — add entries as other MFEs expose parcel widgets.
// parcelName matches a key in the SystemJS importmap (e.g. '@linm/erp-accounting-widget').
const WIDGET_REGISTRY: WidgetConfig[] = [
  { id: 'placeholder-1', title: 'Tổng quan tài chính', cols: 2 },
  { id: 'placeholder-2', title: 'Hoạt động gần đây',   cols: 1 },
  { id: 'placeholder-3', title: 'Nhiệm vụ hôm nay',    cols: 1 },
];

interface WidgetSlotProps {
  config: WidgetConfig;
}

declare const System: { import: (name: string) => Promise<any> };

const WidgetSlot: React.FC<WidgetSlotProps> = ({ config }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!config.parcelName || !containerRef.current) return;

    let parcel: ReturnType<typeof mountRootParcel> | null = null;

    const t = setTimeout(async () => {
      try {
        const parcelModule = await System.import(config.parcelName!);
        if (!parcelModule?.bootstrap || !containerRef.current) return;
        parcel = mountRootParcel(parcelModule, { domElement: containerRef.current });
      } catch {
        // Parcel not available yet — shows placeholder
      }
    }, 0);

    return () => {
      clearTimeout(t);
      parcel?.unmount().catch(() => {});
    };
  }, [config.parcelName]);

  return (
    <div
      className={`${styles.widgetSlot} ${config.cols === 2 ? styles.widgetCols2 : config.cols === 3 ? styles.widgetCols3 : ''}`}
    >
      <div className={styles.widgetHeader}>
        <span className={styles.widgetTitle}>{config.title}</span>
      </div>
      <div ref={containerRef} className={styles.widgetBody}>
        {!config.parcelName && (
          <div className={styles.widgetPlaceholder}>
            <i className="fas fa-chart-bar"></i>
            <span>Widget sẽ được tích hợp từ module tương ứng</span>
          </div>
        )}
      </div>
    </div>
  );
};

const WidgetArea: React.FC = () => (
  <section className={styles.section}>
    <div className={styles.sectionHeader}>
      <h2 className={styles.sectionTitle}>
        <i className="fas fa-th-large"></i> Widgets
      </h2>
    </div>
    <div className={styles.widgetGrid}>
      {WIDGET_REGISTRY.map((w) => (
        <WidgetSlot key={w.id} config={w} />
      ))}
    </div>
  </section>
);

export default WidgetArea;
